const src = $input.item.json;
const eventType = src.event_context?.type || (src.callback ? 'message_callback' : src.message ? 'message_created' : 'bot_started');
const routeRaw = src.callback?.payload ?? src.event_context?.callback_payload ?? src.message?.text ?? src.message?.body?.text ?? src.route ?? (eventType === 'bot_started' ? 'start' : '');
const userId = src.user?.user_id ?? src.metadata?.user_context?.user_id ?? src.message?.sender?.user_id ?? src.callback?.user?.user_id ?? src.user_id ?? null;
const callbackId = src.callback?.callback_id ?? src.callback?.id ?? src.event_context?.callback_id ?? null;
const messageId = src.callback?.message?.body?.mid ?? src.callback?.message?.mid ?? src.callback?.message?.id ?? src.message?.body?.mid ?? src.message?.mid ?? src.message?.id ?? src.event_context?.message_id ?? null;
return {
  json: {
    ...src,
    eventType,
    route: String(routeRaw ?? '').trim().toLowerCase(),
    userId,
    callbackId,
    messageId,
  },
  binary: $input.item.binary,
};

const item = $input.item;
item.binary = item.binary || {};
item.binary.data = {
  data: '',
  mimeType: 'image/jpeg',
  fileName: 'welcome.jpg',
  fileExtension: 'jpg',
};
return item;

